function openProduct(product) {
  if (!product) {
    toast('Producto no encontrado');
    return false;
  }

  currentProduct = product;

  if ($('productHero')) {
    $('productHero').innerHTML = product.imageDataUrl
      ? `<img alt="${escapeHtml(product.name)}" src="${product.imageDataUrl}">`
      : `<div style="font-size:72px">${product.emoji || '🛒'}</div>`;
  }
  if ($('productName')) $('productName').textContent = product.name || 'Producto';
  if ($('productDesc')) $('productDesc').textContent = product.desc || 'Detalle';
  if ($('productListPrice')) $('productListPrice').textContent = money(product.listPrice);
  if ($('productSalePrice')) $('productSalePrice').textContent = product.saleType === 'bundle2'
    ? (product.promoLabel || money(product.salePrice))
    : money(product.salePrice);
  if ($('productDiscount')) $('productDiscount').textContent = product.discountLabel || '-';
  if ($('productCode')) $('productCode').textContent = getProductDisplayCode(product);
  if ($('productFormat')) $('productFormat').textContent = product.format || 'Unidad';

  const clubRow = $('productClubRow');
  const clubPrice = $('productClubPrice');
  if (clubRow && clubPrice) {
    if (customer.isClub) {
      const directClubPrice = product.saleType === 'bundle2'
        ? product.promoLabel || money(Math.round(Number(product.salePrice || 0) * 0.93))
        : money(Math.max(0, Math.round(Number(product.salePrice || 0) * 0.93)));
      clubPrice.textContent = directClubPrice;
      clubRow.classList.remove('hidden');
    } else {
      clubPrice.textContent = '$0';
      clubRow.classList.add('hidden');
    }
  }

  const promo = $('productPromo');
  if (promo) {
    const msgs = [];
    if (product.promoLabel) msgs.push(product.promoLabel);
    if (customer.isClub) msgs.push('Cliente Club: 7% extra sobre el precio oferta');
    if (msgs.length) {
      promo.textContent = msgs.join(' · ');
      promo.classList.remove('hidden');
    } else {
      promo.textContent = '';
      promo.classList.add('hidden');
    }
  }

  renderSearchStatus(`Encontrado: ${product.name}`);
  go('product');
  return true;
}

function openProductByIndex(index) {
  return openProduct(catalog[index]);
}

function openProductByCode(value) {
  const product = findProductByLookup(value);
  if (!product) {
    renderSearchStatus(`No se encontró el código: ${value}`);
    toast(`Código no existe en catálogo: ${value}`, 3000);
    return false;
  }
  return openProduct(product);
}

function scanByCode() {
  const value = $('manualCode')?.value?.trim() || '';
  if (!value) return toast('Ingresa un SKU o código de barras');
  const ok = openProductByCode(value);
  if (ok) toast(`Producto encontrado: ${currentProduct?.name || value}`);
}

function addCurrentProduct() {
  if (!currentProduct) return toast('Primero selecciona un producto');
  const existing = cart.find((item) => item.code === currentProduct.code);
  if (existing) {
    existing.qty = Number(existing.qty || 1) + 1;
  } else {
    cart.push({ ...currentProduct, qty: 1 });
  }
  resetConditionalDiscounts();
  renderCart();
  const name = currentProduct.name;
  clearLookupState();
  toast(`Agregado: ${name}`);
  go('cart');
}

function changeQty(code, delta) {
  const item = cart.find((x) => x.code === code);
  if (!item) return;
  item.qty = Math.max(1, Number(item.qty || 1) + Number(delta || 0));
  resetConditionalDiscounts();
  renderCart();
}

function removeItem(code) {
  cart = cart.filter((x) => x.code !== code);
  resetConditionalDiscounts();
  renderCart();
  toast('Producto eliminado');
}

function renderCart() {
  const list = $('cartList');
  if (!list) return;

  if (!cart.length) {
    list.innerHTML = '<p class="muted">Tu orden está vacía.</p>';
  } else {
    list.innerHTML = cart.map((item) => `
      <div class="cart-item">
        <div class="avatar">${item.imageDataUrl ? `<img alt="${escapeHtml(item.name)}" src="${item.imageDataUrl}">` : (item.emoji || '🛒')}</div>
        <div>
          <strong>${escapeHtml(item.name)}</strong>
          <div class="tiny muted">${escapeHtml(getProductDisplayCode(item))}</div>
          <div class="tiny muted">Cantidad: ${item.qty}</div>
          <div class="tiny muted">Precio lista unitario: ${money(item.listPrice)}</div>
          <div class="tiny muted">Precio oferta aplicado: ${money(calcLineBaseSale(item))}</div>
          <div class="tiny muted">Descuento oferta: ${money((Number(item.listPrice || 0) * Number(item.qty || 1)) - calcLineBaseSale(item))}</div>
          ${customer.isClub ? `<div class="tiny muted" style="margin-top:4px">Descuento Club 7%: ${money(calcLineClubDiscount(item))}</div>` : ''}
          <div class="tiny" style="margin-top:4px;font-weight:700">Total línea final: ${money(calcLineSale(item))}</div>
          ${item.promoLabel ? `<div class="tiny" style="margin-top:4px;color:#7c2d12;font-weight:700">${escapeHtml(item.promoLabel)}</div>` : ''}
          <div class="row" style="gap:8px;margin-top:8px;flex-wrap:wrap">
            <button class="btn btn-secondary btn-small" type="button" onclick="changeQty('${escapeHtml(item.code)}', -1)">-</button>
            <button class="btn btn-secondary btn-small" type="button" onclick="changeQty('${escapeHtml(item.code)}', 1)">+</button>
            <button class="btn btn-danger btn-small" type="button" onclick="removeItem('${escapeHtml(item.code)}')">Quitar</button>
          </div>
        </div>
        <div class="price">${money(calcLineSale(item))}</div>
      </div>
    `).join('');
  }

  if ($('subtotal')) $('subtotal').textContent = money(totalList());
  if ($('saleDiscount')) $('saleDiscount').textContent = money(totalOfferDiscount());
  if ($('clubDiscount')) $('clubDiscount').textContent = money(totalClubDiscount());
  if ($('dermoDiscount')) $('dermoDiscount').textContent = money(totalDermoDiscount());
  if ($('dermoRow')) $('dermoRow').classList.toggle('hidden', totalDermoDiscount() <= 0);
  if ($('discount')) $('discount').textContent = money(totalDiscount());
  if ($('total')) $('total').textContent = money(totalSale());
  if ($('cartStoreHint')) $('cartStoreHint').textContent = storeCode ? `Local ${storeCode}` : 'No informado';
  if ($('cartDermoHint')) {
    if (customerEligibleForDermo()) {
      $('cartDermoHint').textContent = dermoProgramApplied
        ? `Programa DermoCosmética aplicado: ${money(totalDermoDiscount())}`
        : 'Cliente con saldo disponible en programa DermoCosmética';
    } else {
      $('cartDermoHint').textContent = 'Sin beneficios adicionales pendientes';
    }
  }
}

function lookupCustomer() {
  const input = $('customerDoc');
  if (!input) return;
  const clean = rutClean(input.value);
  if (clean.length < 2) return toast('Ingresa un RUT válido');

  const formatted = rutFormat(clean);
  input.value = formatted;

  const found = findClubCustomerByRut(clean);
  if (found) {
    customer = { doc: found.doc || formatted, name: found.name || formatted, isClub: true, lookedUp: true };
    toast(`Cliente Club aplicado: ${customer.name}`);
  } else {
    customer = { doc: formatted, name: formatted, isClub: false, lookedUp: true };
    toast('Cliente no pertenece al Club');
  }

  resetConditionalDiscounts();
  syncCustomerUi();
  renderCart();
  if (currentProduct) openProduct(currentProduct);
  go('cart');
}

function clearCustomer() {
  customer = { doc:'', name:'', isClub:false, lookedUp:false };
  if ($('customerDoc')) $('customerDoc').value = '';
  resetConditionalDiscounts();
  syncCustomerUi();
  renderCart();
  if (currentProduct) openProduct(currentProduct);
  toast('Cliente eliminado');
}

function syncCustomerUi() {
  const name = customer.name || customer.doc || 'Invitado';
  const isKnown = Boolean(customer.lookedUp);
  const isClub = Boolean(customer.isClub);

  if ($('cartCustomerHint')) $('cartCustomerHint').textContent = isKnown ? `${name}${isClub ? ' · Club' : ' · No Club'}` : 'No ingresado';
  if ($('successCustomer')) $('successCustomer').textContent = name;
  if ($('successGreetingName')) $('successGreetingName').textContent = name;
  if ($('receiptCustomerName')) $('receiptCustomerName').textContent = name;

  const navLabel = isKnown ? 'Cambiar cliente' : 'Ingresar cliente';
  if ($('scanCustomerNavBtn')) $('scanCustomerNavBtn').textContent = navLabel;
  if ($('cartCustomerNavBtn')) $('cartCustomerNavBtn').textContent = navLabel;
  if ($('lookupCustomerBtn')) $('lookupCustomerBtn').textContent = isKnown ? 'Actualizar cliente' : 'Aplicar cliente';
  if ($('clearCustomerBtn')) $('clearCustomerBtn').classList.toggle('hidden', !isKnown);

  const pairs = [
    ['scanClubBanner','clubCustomerNameScan','scanNonClubBanner','nonClubCustomerNameScan'],
    ['cartClubBanner','clubCustomerNameCart','cartNonClubBanner','nonClubCustomerNameCart'],
    ['clubBanner','clubCustomerName','nonClubBanner','nonClubCustomerName']
  ];

  for (const [clubId, clubNameId, nonClubId, nonClubNameId] of pairs) {
    const clubEl = $(clubId);
    const clubNameEl = $(clubNameId);
    const nonClubEl = $(nonClubId);
    const nonClubNameEl = $(nonClubNameId);

    if (clubEl) clubEl.classList.toggle('hidden', !(isKnown && isClub));
    if (clubNameEl) clubNameEl.textContent = name;
    if (nonClubEl) nonClubEl.classList.toggle('hidden', !(isKnown && !isClub));
    if (nonClubNameEl) nonClubNameEl.textContent = name;
  }
}

function syncStoreUi() {
  if ($('storeCode')) {
    const normalized = storeInputNormalize($('storeCode').value || storeCode);
    if ($('storeCode').value !== normalized) $('storeCode').value = normalized;
  }
  if ($('storeDisplayScan')) $('storeDisplayScan').textContent = storeCode ? `Local ${storeCode}` : 'Local no informado';
  if ($('paymentStoreText')) $('paymentStoreText').textContent = storeCode ? `Local ${storeCode}` : 'Local no informado';
  if ($('successStoreText')) $('successStoreText').textContent = storeCode ? `Gracias por comprar en Local ${storeCode}` : 'Gracias por comprar';
}

function selectMethodCard(el) {
  selectedMethod = el?.dataset?.method || 'qr';
  document.querySelectorAll('.pay-option').forEach((x) => x.classList.toggle('active', x === el));
  updateWalletPayCopy();
}

function selectSubOption(el) {
  selectedSubOption = el?.dataset?.sub || 'redcompra';
  document.querySelectorAll('#webpaySuboptions .subopt').forEach((x) => x.classList.toggle('active', x === el));
  updateWalletPayCopy();
}

function updateWalletPayCopy() {
  const webpaySubs = $('webpaySuboptions');
  const title = $('walletTitle');
  const desc = $('walletDesc');
  const badge = $('walletMethodBadge');
  const processingBox = $('processingBox');

  if (processingBox) processingBox.classList.add('hidden');
  if (webpaySubs) webpaySubs.classList.toggle('hidden', selectedMethod !== 'webpay');

  if (selectedMethod === 'qr') {
    if (title) title.textContent = 'QR hacia POS';
    if (desc) desc.textContent = 'Pago QR presentado al POS.';
    if (badge) badge.textContent = 'qr';
    return;
  }

  if (selectedMethod === 'webpay') {
    const labels = { redcompra:'Redcompra', visa:'Crédito Visa', master:'Crédito MasterCard' };
    if (title) title.textContent = 'Webpay (Transbank)';
    if (desc) desc.textContent = `Simulación de pago por ${labels[selectedSubOption] || 'Transbank'}.`;
    if (badge) badge.textContent = selectedSubOption;
    return;
  }

  if (selectedMethod === 'gpay') {
    if (title) title.textContent = 'Google Pay';
    if (desc) desc.textContent = 'Simulación de wallet Android.';
    if (badge) badge.textContent = 'gpay';
    return;
  }

  if (selectedMethod === 'mp') {
    if (title) title.textContent = 'Mercado Pago';
    if (desc) desc.textContent = 'Simulación de wallet Mercado Pago.';
    if (badge) badge.textContent = 'mp';
  }
}

function renderPaymentSummary() {
  if ($('paymentTotal')) $('paymentTotal').textContent = money(totalSale());
  if ($('paymentSubtotal')) $('paymentSubtotal').textContent = money(totalList());
  if ($('paymentOfferDiscount')) $('paymentOfferDiscount').textContent = money(totalOfferDiscount());
  if ($('paymentClubDiscount')) $('paymentClubDiscount').textContent = money(totalClubDiscount());
  if ($('paymentDermoDiscount')) $('paymentDermoDiscount').textContent = money(totalDermoDiscount());
  if ($('paymentDermoRow')) $('paymentDermoRow').classList.toggle('hidden', totalDermoDiscount() <= 0);
  if ($('paymentStoreText')) $('paymentStoreText').textContent = storeCode ? `Local ${storeCode}` : 'Local no informado';
  if ($('paymentCustomerText')) $('paymentCustomerText').textContent = customer.lookedUp ? activeCustomerName() : 'Invitado';
  if ($('paymentDermoHint')) {
    if (customerEligibleForDermo()) {
      $('paymentDermoHint').textContent = dermoProgramApplied
        ? `Canje programa DermoCosmética aplicado: ${money(totalDermoDiscount())}`
        : 'Cliente con saldo disponible para canje DermoCosmética';
    } else {
      $('paymentDermoHint').textContent = 'Sin canjes especiales';
    }
  }
}

function validateStoreBeforePayment() {
  if (!storeCode) {
    toast('Ingresa el local antes de pagar');
    go('home');
    const input = $('storeCode');
    if (input) input.focus();
    return false;
  }
  return true;
}

function openDermoModal() {
  const modal = $('dermoModal');
  if (modal) modal.classList.remove('hidden');
}

function closeDermoModal() {
  const modal = $('dermoModal');
  if (modal) modal.classList.add('hidden');
}

function handleGoPayment() {
  if (!cart.length) return toast('Agrega al menos un producto');
  if (!validateStoreBeforePayment()) return;

  if (customerEligibleForDermo() && !dermoPromptAnswered) {
    openDermoModal();
    return;
  }

  go('payment');
}

function applyDermoDecision(apply) {
  dermoPromptAnswered = true;
  dermoProgramApplied = Boolean(apply);
  closeDermoModal();
  renderCart();
  renderPaymentSummary();
  if (apply) toast(`Dcto. Prog. Dermo ${money(totalDermoDiscount())}`);
  go('payment');
}

function continuePayment() {
  if (!cart.length) return toast('Agrega al menos un producto');
  if (!validateStoreBeforePayment()) return;
  if (selectedMethod === 'qr') return go('qrpay');
  go('walletpay');
}

function saleMethodLabel() {
  if (selectedMethod === 'qr') return 'QR hacia POS';
  if (selectedMethod === 'gpay') return 'Google Pay';
  if (selectedMethod === 'mp') return 'Mercado Pago';
  if (selectedMethod === 'webpay') {
    const labels = { redcompra:'Webpay Redcompra', visa:'Webpay Visa', master:'Webpay MasterCard' };
    return labels[selectedSubOption] || 'Webpay';
  }
  return 'Pago digital';
}

function buildPaymentReference() {
  const now = new Date();
  const stamp = `${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}${String(now.getHours()).padStart(2,'0')}${String(now.getMinutes()).padStart(2,'0')}${String(now.getSeconds()).padStart(2,'0')}`;
  return `TBK D NU.${String(storeCode || '0000').padStart(4,'0')}${stamp}`;
}

function buildSaleRecord() {
  const now = new Date();
  const dd = String(now.getDate()).padStart(2,'0');
  const mm = String(now.getMonth() + 1).padStart(2,'0');
  const yyyy = now.getFullYear();
  const hh = String(now.getHours()).padStart(2,'0');
  const mi = String(now.getMinutes()).padStart(2,'0');
  const ss = String(now.getSeconds()).padStart(2,'0');
  const total = totalSale();
  const neto = Math.round(total / 1.19);
  const iva = total - neto;
  const folio = `${yyyy}${String(orderCounter).padStart(6,'0')}`.slice(-10);
  const boletaNumber = `${Math.floor(1000000000 + Math.random() * 8999999999)}`;

  return {
    order: `C${Math.floor(10000000 + Math.random() * 89999999)}`,
    boletaNumber,
    folio,
    dateText: `${dd}/${mm}/${yyyy}`,
    dateTimeText: `${dd}-${mm}-${yyyy} Hora: ${hh}:${mi}:${ss}`,
    storeCode: storeCode || '0000',
    customer: { ...customer },
    items: cart.map((item) => ({ ...item })),
    subtotalList: totalList(),
    offerDiscount: totalOfferDiscount(),
    clubDiscount: totalClubDiscount(),
    dermoDiscount: totalDermoDiscount(),
    total,
    totalNeto: neto,
    totalIva: iva,
    productCount: cart.length,
    totalUnits: cart.reduce((a, item) => a + Number(item.qty || 1), 0),
    paymentLabel: saleMethodLabel(),
    paymentReference: buildPaymentReference(),
    seller: { ...MOCK_VENDOR },
    isClub: customer.isClub,
    dermoApplied: dermoProgramApplied
  };
}

function finalizeSale() {
  lastSale = buildSaleRecord();
  if ($('successOrder')) $('successOrder').textContent = lastSale.order;
  if ($('successTotal')) $('successTotal').textContent = money(lastSale.total);
  if ($('successCustomer')) $('successCustomer').textContent = activeCustomerName();
  if ($('successFolio')) $('successFolio').textContent = lastSale.folio;
  if ($('successDate')) $('successDate').textContent = lastSale.dateText;
  if ($('successStoreText')) $('successStoreText').textContent = `Gracias por comprar en Local ${lastSale.storeCode}`;
  go('success');
}

function simulateProcessingAndApprove(message) {
  const processingBox = $('processingBox');
  if (processingBox) processingBox.classList.remove('hidden');
  if ($('processingTitle')) $('processingTitle').textContent = 'Procesando pago…';
  if ($('processingSubtitle')) $('processingSubtitle').textContent = message || 'Conectando con el proveedor';

  setTimeout(() => {
    if (processingBox) processingBox.classList.add('hidden');
    finalizeSale();
  }, 1100);
}

function simulateQrApprove() {
  finalizeSale();
}

function simulateProcessingAndFail() {
  const processingBox = $('processingBox');
  if (processingBox) processingBox.classList.add('hidden');
  toast('Pago rechazado');
}

function renderSuccess() {
  if (!lastSale) return;
  if ($('successOrder')) $('successOrder').textContent = lastSale.order;
  if ($('successFolio')) $('successFolio').textContent = lastSale.folio;
  if ($('successDate')) $('successDate').textContent = lastSale.dateText;
  if ($('successTotal')) $('successTotal').textContent = money(lastSale.total);
  if ($('successCustomer')) $('successCustomer').textContent = lastSale.customer.name || lastSale.customer.doc || 'Invitado';
  if ($('successGreetingName')) $('successGreetingName').textContent = lastSale.customer.name || lastSale.customer.doc || 'CLIENTE';
  if ($('successStoreText')) $('successStoreText').textContent = `Gracias por comprar en Local ${lastSale.storeCode}`;
}

function receiptDiscountLinesHtml(sale) {
  const rows = [];
  if (sale.offerDiscount > 0) rows.push(`<div class="receipt-row discount"><span>***DESCUENTO FCV</span><strong>-${money(sale.offerDiscount)}</strong></div>`);
  if (sale.clubDiscount > 0) rows.push(`<div class="receipt-row discount"><span>***DESCUENTO CLUB 7%</span><strong>-${money(sale.clubDiscount)}</strong></div>`);
  if (sale.dermoDiscount > 0) rows.push(`<div class="receipt-row discount"><span>Dcto. Prog. Dermo</span><strong>-${money(sale.dermoDiscount)}</strong></div>`);
  return rows.join('');
}

