function newOrder() {
  cart = [];
  clearLookupState();
  selectedMethod = 'qr';
  selectedSubOption = 'redcompra';
  orderCounter += 1;
  document.querySelectorAll('.pay-option').forEach((x) => x.classList.toggle('active', x.dataset.method === 'qr'));
  document.querySelectorAll('#webpaySuboptions .subopt').forEach((x) => x.classList.toggle('active', x.dataset.sub === 'redcompra'));
  stopScannerSession({ keepIntent: false });
  cameraRequested = false;
  shouldResumeCamera = false;
  customer = { doc:'', name:'', isClub:false, lookedUp:false };
  lastSale = null;
  storeCode = '';
  if ($('customerDoc')) $('customerDoc').value = '';
  if ($('storeCode')) $('storeCode').value = '';
  resetConditionalDiscounts();
  renderCart();
  go('home');
  toast('Nueva compra iniciada');
}

function updateBarcodeSupportBadge(active = false) {
  const badge = $('barcodeSupport');
  if (!badge) return;
  if (!('BarcodeDetector' in window)) {
    badge.textContent = 'Cámara OK / detección manual';
    badge.className = 'badge badge-warn';
    return;
  }
  if (active) {
    badge.textContent = 'Escaneo automático activo';
    badge.className = 'badge badge-ok';
    return;
  }
  badge.textContent = 'Escaneo automático disponible';
  badge.className = 'badge badge-info';
}

function showVideoFallback(message) {
  const fallback = $('videoFallback');
  const videoEl = $('video');
  if (videoEl) {
    videoEl.classList.add('hidden');
    videoEl.classList.remove('ready');
  }
  if (fallback) {
    fallback.textContent = message;
    fallback.classList.remove('hidden');
  }
}

function hideVideoFallback() {
  const fallback = $('videoFallback');
  const videoEl = $('video');
  if (fallback) fallback.classList.add('hidden');
  if (videoEl) {
    videoEl.classList.remove('hidden');
    videoEl.classList.add('ready');
  }
}

function stopTracksOnly() {
  if (stream) {
    stream.getTracks().forEach((track) => {
      try { track.stop(); } catch (_) {}
    });
    stream = null;
  }
}

function stopScannerSession(options = {}) {
  scanningActive = false;
  detector = null;
  if (scanLoopHandle) cancelAnimationFrame(scanLoopHandle);
  scanLoopHandle = null;

  stopTracksOnly();

  const videoEl = $('video');
  if (videoEl) {
    try { videoEl.pause(); } catch (_) {}
    videoEl.srcObject = null;
  }

  if (!options.keepIntent) {
    cameraRequested = false;
    shouldResumeCamera = false;
  } else {
    shouldResumeCamera = true;
  }

  if (!options.keepFallback) {
    showVideoFallback('Toca el botón scanner para abrir la cámara. Luego el producto se detecta solo.');
  }
  updateBarcodeSupportBadge(false);
}

async function getCameraStream() {
  const attempts = [
    {
      video: {
        facingMode: { ideal: 'environment' },
        width: { ideal: 1280 },
        height: { ideal: 720 }
      },
      audio: false
    },
    {
      video: { facingMode: 'environment' },
      audio: false
    },
    {
      video: true,
      audio: false
    }
  ];

  let lastError = null;
  for (const constraints of attempts) {
    try {
      return await navigator.mediaDevices.getUserMedia(constraints);
    } catch (err) {
      lastError = err;
    }
  }
  throw lastError || new Error('No se pudo abrir la cámara');
}

function waitForVideoReady(videoEl, timeout = 2500) {
  return new Promise((resolve, reject) => {
    const started = Date.now();
    const tick = async () => {
      if (videoEl.readyState >= 2 && videoEl.videoWidth > 0 && videoEl.videoHeight > 0) {
        return resolve(true);
      }
      if (Date.now() - started > timeout) {
        return reject(new Error('La cámara no entregó imagen'));
      }
      setTimeout(tick, 100);
    };
    tick();
  });
}

async function startCamera(options = {}) {
  if (cameraStartInProgress) return;
  if (!navigator.mediaDevices?.getUserMedia) {
    toast('Este navegador no permite cámara en este contexto.');
    showVideoFallback('Este navegador no permite abrir la cámara aquí.');
    return;
  }

  cameraStartInProgress = true;
  if (!options.silent) {
    cameraRequested = true;
    shouldResumeCamera = true;
  }

  const videoEl = $('video');
  try {
    stopScannerSession({ keepIntent: true, keepFallback: true });
    showVideoFallback('Abriendo cámara…');
    updateBarcodeSupportBadge(false);

    stream = await getCameraStream();
    if (!videoEl) throw new Error('No existe el video');
    videoEl.setAttribute('playsinline', 'true');
    videoEl.setAttribute('autoplay', 'true');
    videoEl.muted = true;
    videoEl.srcObject = stream;

    hideVideoFallback();

    try { await videoEl.play(); } catch (_) {}
    await waitForVideoReady(videoEl, 3000);

    hideVideoFallback();
    cameraRequested = true;
    shouldResumeCamera = true;
    toast(options.silent ? 'Cámara reanudada' : 'Cámara activa. Buscando producto…', 1800);
    startAutomaticDetection();
  } catch (err) {
    console.error('startCamera', err);
    stopScannerSession({ keepIntent: false });
    showVideoFallback('No se pudo iniciar la cámara. Revisa permisos y vuelve a intentarlo.');
    toast('No se pudo iniciar la cámara. Usa ingreso manual.', 3200);
  } finally {
    cameraStartInProgress = false;
  }
}

function startAutomaticDetection() {
  if (!stream) return;
  if (!('BarcodeDetector' in window)) {
    updateBarcodeSupportBadge(false);
    toast('La cámara quedó activa. Si no detecta automático, usa búsqueda manual.', 2600);
    return;
  }

  try {
    detector = new BarcodeDetector({ formats: ['ean_13','ean_8','upc_a','upc_e','code_128','code_39','code_93'] });
  } catch (err) {
    console.error('BarcodeDetector', err);
    detector = null;
    updateBarcodeSupportBadge(false);
    return;
  }

  scanningActive = true;
  updateBarcodeSupportBadge(true);
  scanLoop();
}

function handleDetectedCode(raw) {
  const value = String(raw || '').trim();
  if (!value) return;
  if ($('manualCode')) $('manualCode').value = value;

  const product = findProductByLookup(value);
  if (!product) {
    renderSearchStatus(`Código detectado sin coincidencia: ${value}`);
    toast(`Código no existe en catálogo: ${value}`, 2600);
    return;
  }

  openProduct(product);
  toast(`Código detectado: ${value}`, 1800);
}

async function scanLoop() {
  if (!scanningActive || !detector || !stream || activeScreenId() !== 'scan') return;
  const videoEl = $('video');
  try {
    if (videoEl && videoEl.readyState >= 2 && videoEl.videoWidth > 0) {
      const codes = await detector.detect(videoEl);
      if (codes && codes.length) {
        const raw = String(codes[0].rawValue || '').trim();
        const key = digitsOnly(raw) || normalizeLookup(raw);
        const now = Date.now();
        if (raw && (key !== lastDetectedKey || (now - lastDetectedAt) > 1400)) {
          lastDetectedKey = key;
          lastDetectedAt = now;
          handleDetectedCode(raw);
          return;
        }
      }
    }
  } catch (err) {
    console.debug('scanLoop', err);
  }
  scanLoopHandle = requestAnimationFrame(scanLoop);
}

function printReceipt() {
  window.print();
}

function bindEvents() {
  document.querySelectorAll('[data-go]').forEach((btn) => btn.addEventListener('click', () => go(btn.dataset.go)));

  $('goScanBtn')?.addEventListener('click', () => go('scan'));
  $('cameraBtn')?.addEventListener('click', () => startCamera());
  $('manualSearchBtn')?.addEventListener('click', scanByCode);
  $('manualCode')?.addEventListener('keydown', (ev) => { if (ev.key === 'Enter') scanByCode(); });
  $('lookupCustomerBtn')?.addEventListener('click', lookupCustomer);
  $('clearCustomerBtn')?.addEventListener('click', clearCustomer);
  $('addProductBtn')?.addEventListener('click', addCurrentProduct);
  $('goPaymentBtn')?.addEventListener('click', handleGoPayment);
  $('continuePaymentBtn')?.addEventListener('click', continuePayment);
  $('approveQrBtn')?.addEventListener('click', simulateQrApprove);
  $('approveWalletBtn')?.addEventListener('click', () => simulateProcessingAndApprove());
  $('failPayBtn')?.addEventListener('click', simulateProcessingAndFail);
  $('newOrderBtn')?.addEventListener('click', newOrder);
  $('viewReceiptBtn')?.addEventListener('click', () => go('receipt'));
  $('receiptBackBtn')?.addEventListener('click', () => go('success'));
  $('receiptPrintBtn')?.addEventListener('click', printReceipt);
  $('dermoYesBtn')?.addEventListener('click', () => applyDermoDecision(true));
  $('dermoNoBtn')?.addEventListener('click', () => applyDermoDecision(false));

  $('customerDoc')?.addEventListener('input', (ev) => {
    const clean = rutClean(ev.target.value);
    ev.target.value = rutFormat(clean);
  });

  $('storeCode')?.addEventListener('input', (ev) => {
    storeCode = storeInputNormalize(ev.target.value);
    ev.target.value = storeCode;
    syncStoreUi();
  });

  document.querySelectorAll('.pay-option').forEach((el) => el.addEventListener('click', () => selectMethodCard(el)));
  document.querySelectorAll('#webpaySuboptions .subopt').forEach((el) => el.addEventListener('click', () => selectSubOption(el)));

  document.addEventListener('visibilitychange', () => {
    if (document.hidden) {
      if (stream) stopScannerSession({ keepIntent: cameraRequested, keepFallback: true });
      return;
    }
    if (!document.hidden && activeScreenId() === 'scan' && (cameraRequested || shouldResumeCamera)) {
      setTimeout(() => startCamera({ silent: true }), 250);
    }
  });

  window.addEventListener('pageshow', () => {
    if (activeScreenId() === 'scan' && (cameraRequested || shouldResumeCamera)) {
      setTimeout(() => startCamera({ silent: true }), 250);
    }
  });
}

function init() {
  bindEvents();
  updateBarcodeSupportBadge(false);
  renderSearchStatus();
  renderCatalogAdmin();
  renderCart();
  syncCustomerUi();
  syncStoreUi();
  updateWalletPayCopy();
}

window.openProductByIndex = openProductByIndex;
window.openProductByCode = openProductByCode;
window.changeQty = changeQty;
window.removeItem = removeItem;

init();
